const PI2o6 = Math.PI*Math.PI/6;
const slider = $('#bp-n'), lbl = $('#bp-n-lbl'), out = $('#bp-out'), svg = $('#bp-svg');
function draw(){
  const N = parseInt(slider.value,10);
  lbl.textContent = 'N = '+N;
  let s = 0;
  for(let k=1;k<=N;k++) s += 1/(k*k);
  out.textContent = `S_${N} = ${s.toFixed(10)}\nπ²/6  = ${PI2o6.toFixed(10)}\nerror = ${(PI2o6-s).toFixed(10)}`;
  // draw convergence plot
  svg.innerHTML='';
  const W=620, H=200, padL=52, padR=20, padT=16, padB=30;
  const Npts = Math.min(N,200);
  const partial = [];
  let acc = 0;
  for(let k=1;k<=Npts;k++){ acc+=1/(k*k); partial.push(acc); }
  const yMin = partial[0]*0.9, yMax = PI2o6*1.04;
  const xP = k => padL + (k/(Npts))*(W-padL-padR);
  const yP = v => (H-padB) - (v-yMin)/(yMax-yMin)*(H-padT-padB);
  // axes
  svg.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--line)','stroke-width':1}));
  // y ticks
  [1.0,1.2,1.4,1.6].forEach(v=>{
    const y = yP(v);
    if(y<padT||y>H-padB) return;
    svg.appendChild(SVG('line',{x1:padL-4,y1:y,x2:padL,y2:y,stroke:'var(--mute)'}));
    const t=SVG('text',{x:padL-6,y:y+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'}); t.textContent=v.toFixed(1); svg.appendChild(t);
  });
  // target line
  const yTarget = yP(PI2o6);
  const dash = SVG('line',{x1:padL,y1:yTarget,x2:W-padR,y2:yTarget,stroke:'var(--yellow)','stroke-width':1.5,'stroke-dasharray':'6 4'});
  svg.appendChild(dash);
  const tLbl = SVG('text',{x:W-padR-2,y:yTarget-5,'text-anchor':'end','font-size':10,fill:'var(--yellow)'}); tLbl.textContent='π²/6'; svg.appendChild(tLbl);
  // partial sum curve
  const pts = partial.map((v,i)=>`${xP(i+1)} ${yP(v)}`).join(' L ');
  svg.appendChild(SVG('polyline',{points:partial.map((v,i)=>`${xP(i+1)},${yP(v)}`).join(' '),fill:'none',stroke:'var(--cyan)','stroke-width':1.8}));
}
slider.addEventListener('input', draw);
draw();

