// Bernoulli numbers (even indices) — precomputed rationals as [num,den] BigInt pairs
const BERN = {
  2:[1n,6n], 4:[-1n,30n], 6:[1n,42n], 8:[-1n,30n],
  10:[5n,66n], 12:[-691n,2730n], 14:[7n,6n], 16:[-3617n,510n]
};
function bernoulli(k){ const b = BERN[k]; return b ? Number(b[0])/Number(b[1]) : 0; }
function zetaFormula(n){
  // (-1)^{n+1} B_{2n} (2pi)^{2n} / (2 (2n)!)
  const B = bernoulli(2*n);
  const sign = ((n+1)%2===0) ? -1 : 1;
  let fact = 1;
  for(let i=1;i<=2*n;i++) fact*=i;
  return sign * B * Math.pow(2*Math.PI, 2*n) / (2 * fact);
}
function zetaPartial(n, N){
  let s = 0;
  for(let k=1;k<=N;k++) s += Math.pow(k, -2*n);
  return s;
}

const nEl=$('#ev-n'), NEl=$('#ev-N'), nLbl=$('#ev-n-lbl'), NLbl=$('#ev-N-lbl');
const out=$('#ev-out'), svg=$('#ev-svg');

function draw(){
  const n=parseInt(nEl.value,10), N=parseInt(NEl.value,10);
  nLbl.textContent='n = '+n;
  NLbl.textContent='N = '+N;
  const exact=zetaFormula(n), partial=zetaPartial(n,N);
  const fmtMap={1:'π²/6',2:'π⁴/90',3:'π⁶/945',4:'π⁸/9450',5:'π¹⁰/93555'};
  out.textContent =
    `ζ(${2*n}) formula  = ${exact.toFixed(10)}  [= ${fmtMap[n]||'…'}]\n`+
    `ζ(${2*n}) partial (${N} terms) = ${partial.toFixed(10)}\n`+
    `error = ${(exact-partial).toExponential(4)}`;
  // bar chart of first 30 terms
  svg.innerHTML='';
  const W=620,H=180,padL=50,padR=20,padT=14,padB=30;
  const M=30;
  const vals = Array.from({length:M},(_, i)=>Math.pow(i+1,-2*n));
  const yMax = vals[0]*1.08;
  const xP=i=>padL+(i+0.5)*(W-padL-padR)/M;
  const yP=v=>(H-padB)-(v/yMax)*(H-padT-padB);
  const bw=(W-padL-padR)/M*0.6;
  svg.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--line)'}));
  // y axis label
  const ylbl=SVG('text',{x:padL-6,y:padT+5,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
  ylbl.textContent='k⁻²ⁿ'; svg.appendChild(ylbl);
  vals.forEach((v,i)=>{
    const x=xP(i), y=yP(v);
    const bar=SVG('rect',{x:x-bw/2,y,width:bw,height:(H-padB)-y,
      fill:`rgba(125,224,214,0.6)`,stroke:'var(--cyan)','stroke-width':0.7});
    svg.appendChild(bar);
    if(i%5===0){
      const t=SVG('text',{x,y:H-padB+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
      t.textContent=i+1; svg.appendChild(t);
    }
  });
}
nEl.addEventListener('input',draw);
NEl.addEventListener('input',draw);
draw();

