const ZETA3 = 1.2020569031595943;
// central binomial C(2k,k)
function cbinom(k){ let r=1; for(let i=1;i<=k;i++) r = r*(k+i)/i; return r; }
// partial sums of Apery series S_N = 5/2 * sum_{k=1}^N (-1)^{k+1} / (k^3 * C(2k,k))
function aperyPartial(N){
  let s=0;
  for(let k=1;k<=N;k++){
    s += (k%2===1?1:-1) / (k*k*k * cbinom(k));
  }
  return 2.5*s;
}

const sliderEl=$('#ap-n'), lblEl=$('#ap-n-lbl'), outEl=$('#ap-out'), svgEl=$('#ap-svg');
function draw(){
  const N = parseInt(sliderEl.value,10);
  lblEl.textContent = 'N = '+N;
  const Npts = Math.max(N, 1);
  const pts = [];
  for(let k=1;k<=Npts;k++) pts.push(aperyPartial(k));
  const pN = pts[Npts-1];
  outEl.textContent =
    `Apery partial sum (${N} terms) = ${pN.toFixed(12)}\n`+
    `ζ(3)                           = ${ZETA3.toFixed(12)}\n`+
    `error                          = ${Math.abs(ZETA3-pN).toExponential(4)}`;
  // draw
  const W=620,H=220,padL=52,padR=20,padT=16,padB=30;
  svgEl.innerHTML='';
  const allY = pts.concat([ZETA3]);
  const yMin=Math.min(...allY)*0.985, yMax=Math.max(...allY)*1.01;
  const xP=i=>padL+(i/Npts)*(W-padL-padR);
  const yP=v=>(H-padB)-(v-yMin)/(yMax-yMin)*(H-padT-padB);
  // axes
  svgEl.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--line)'}));
  svgEl.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--line)'}));
  // target
  const yt=yP(ZETA3);
  svgEl.appendChild(SVG('line',{x1:padL,y1:yt,x2:W-padR,y2:yt,stroke:'var(--yellow)','stroke-width':1.5,'stroke-dasharray':'6 4'}));
  const tl=SVG('text',{x:W-padR-2,y:yt-5,'text-anchor':'end','font-size':10,fill:'var(--yellow)'}); tl.textContent='ζ(3)'; svgEl.appendChild(tl);
  // plot curve
  if(pts.length>1){
    const d=pts.map((v,i)=>(i===0?'M':'L')+xP(i+1)+' '+yP(v)).join(' ');
    svgEl.appendChild(SVG('path',{d,fill:'none',stroke:'rgba(224,122,95,0.55)','stroke-width':1.5}));
  }
  // dots
  pts.forEach((v,i)=>{
    svgEl.appendChild(SVG('circle',{cx:xP(i+1),cy:yP(v),r:4,fill:'var(--pink)',stroke:'none'}));
  });
  // x ticks
  for(let i=1;i<=Npts;i+=Math.max(1,Math.floor(Npts/8))){
    const x=xP(i);
    svgEl.appendChild(SVG('line',{x1:x,y1:H-padB,x2:x,y2:H-padB+4,stroke:'var(--mute)'}));
    const t=SVG('text',{x,y:H-padB+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'}); t.textContent=i; svgEl.appendChild(t);
  }
}
sliderEl.addEventListener('input', draw);
draw();

