// B_n for n=0..13
const BRAT = [
  [1n,1n],[-1n,2n],[1n,6n],[0n,1n],[-1n,30n],[0n,1n],[1n,42n],[0n,1n],
  [-1n,30n],[0n,1n],[5n,66n],[0n,1n],[-691n,2730n],[0n,1n]
];
// zeta(-n) = -B_{n+1}/(n+1)
function zetaNeg(n){
  const [num,den] = BRAT[n+1] || [0n,1n];
  // -num/(den*(n+1))
  return -Number(num)/(Number(den)*(n+1));
}
function bernStr(k){
  const [num,den]=BRAT[k]||[0n,1n];
  if(num===0n) return '0';
  return (den===1n) ? num.toString() : `${num}/${den}`;
}

const slider=$('#neg-n'), lbl=$('#neg-n-lbl'), out=$('#neg-out'), svg=$('#neg-svg');
function draw(){
  const n=parseInt(slider.value,10);
  lbl.textContent='n = '+n;
  const val=zetaNeg(n);
  const Bn1=bernStr(n+1);
  out.textContent =
    `ζ(−${n}) = −B_{${n+1}}/(${n+1}) = −(${Bn1})/${n+1} = ${val===0?'0':val.toFixed(8)}\n`+
    (n%2===0 && n>=2 ? `[trivial zero: B_{${n+1}} = 0 since ${n+1} is odd and ≥3]` :
     n===0 ? `[ζ(0) = −1/2]` : '');
  // bar chart n=0..12
  const vals=[];
  for(let k=0;k<=12;k++) vals.push(zetaNeg(k));
  svg.innerHTML='';
  const W=620,H=240,padL=60,padR=20,padT=16,padB=30;
  const M=13;
  const yAbsMax=Math.max(...vals.map(Math.abs))*1.15 || 0.1;
  const yMid=H/2;
  const yScale=(H/2-padT-8)/yAbsMax;
  const xP=i=>padL+(i+0.5)*(W-padL-padR)/M;
  const bw=(W-padL-padR)/M*0.5;
  // zero axis
  svg.appendChild(SVG('line',{x1:padL,y1:yMid,x2:W-padR,y2:yMid,stroke:'var(--line)'}));
  // y labels
  [-0.1,-0.05,0,0.05,0.1].forEach(v=>{
    const y=yMid-v*yScale;
    if(y<padT||y>H-padB) return;
    const t=SVG('text',{x:padL-5,y:y+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
    t.textContent=v.toFixed(2); svg.appendChild(t);
  });
  vals.forEach((v,i)=>{
    const x=xP(i);
    const isSel=(i===n);
    const isZero=(v===0);
    const y0=yMid, y1=yMid-v*yScale;
    const color=isZero?'rgba(180,180,180,0.3)': isSel?'var(--yellow)':'rgba(179,157,219,0.65)';
    if(!isZero){
      svg.appendChild(SVG('rect',{
        x:x-bw/2,y:Math.min(y0,y1),width:bw,height:Math.abs(y1-y0),
        fill:color,stroke:isSel?'var(--yellow)':'var(--violet)','stroke-width':isSel?2:0.7
      }));
    } else {
      svg.appendChild(SVG('circle',{cx:x,cy:yMid,r:5,fill:'none',stroke:'var(--mute)','stroke-width':1.5}));
    }
    const t=SVG('text',{x,y:H-padB+14,'text-anchor':'middle','font-size':10,fill:isSel?'var(--yellow)':'var(--mute)'});
    t.textContent='-'+i; svg.appendChild(t);
  });
}
