// Gamma function (real, positive argument only needed here for display)
function gammaReal(x){
  if(x<0.5) return Math.PI/(Math.sin(Math.PI*x)*gammaReal(1-x));
  x -= 1;
  const g=7;
  const p=[0.99999999999980993,676.5203681218851,-1259.1392167224028,
    771.32342877765313,-176.61502916214059,12.507343278686905,
    -0.13857109526572012,9.9843695780195716e-6,1.5056327351493116e-7];
  let t=x+g+0.5;
  let s=p[0];
  for(let i=1;i<=g+1;i++) s+=p[i]/(x+i);
  return Math.sqrt(2*Math.PI)*Math.pow(t,x+0.5)*Math.exp(-t)*s;
}
// zeta(s) for real s > 1 via Euler-Maclaurin style partial sum + tail correction
function zetaReal(s){
  if(s<=1) return null;
  let acc=0;
  const N=200;
  for(let k=1;k<=N;k++) acc+=Math.pow(k,-s);
  // tail integral correction: sum_{k>N} k^{-s} ≈ integral_N^inf x^{-s} dx = N^{1-s}/(s-1)
  acc += Math.pow(N,1-s)/(s-1);
  return acc;
}

